export function Node(tree, row, column, level, tag, name) {
    (this.value = name),
        (this.depth = level),
        (this.depthbyrow = row),
        (this.depthbycolumn = column),
        (this.childIndexbyrow = 0),
        (this.childIndexbycolumn = 0),
        (this.tag = tag),
        (this.data = tree.data);
    this.node = tree;
}

function getDepth() {
    let node = this;
    let depth = node.tag == 'row' ? node.depthbyrow : node.depthbycolumn;
    return depth;
}

Node.prototype = {
    getDepth: getDepth
};
